const getEPPDetails = async (from, to) => {
    const { purchases, customerMap, userMap } = await _getPurchaseBase();
    const map = {};
    for (const p of purchases) {
        if (p.payment_method !== 'EPP' || p.date < from || p.date > to) continue;
        if (!_passesPurchaseFilter(p, _getPurchaseAgentId(p, customerMap), userMap)) continue;
        const bank = p.epp_bank || 'Unknown';
        const months = p.epp_months || '-';
        const key = `${bank}||${months}`;
        if (!map[key]) map[key] = { bank, months, count: 0 };
        map[key].count++;
    }
    return Object.values(map);
};

const getNewAgents = async (from, to) => {
    const users = await AppDataStore.getAll('users');
    let count = 0;
    for (const u of users) {
        if (u.join_date < from || u.join_date > to) continue;
        if (_visibleUserIds !== 'all' && !_visibleUserIds.includes(u.id)) continue;
        if (_currentRoleFilter !== 'All') {
            if (u.role !== _currentRoleFilter) continue;
        } else {
            if (!isAgent(u)) continue;
        }
        count++;
    }
    return count;
};

// Active agents: agents with any activity log or event attendance in the past 60 days.
// Window is FIXED at 60 days back from today — independent of the KPI time filter.
const getActiveAgents = async () => {
    const cutoff = new Date();
    cutoff.setDate(cutoff.getDate() - 60);
    const cutoffStr = cutoff.toISOString().slice(0, 10);

    const [users, allActivities, allAttendees] = await Promise.all([
        AppDataStore.getAll('users'),
        AppDataStore.getAll('activities'),
        AppDataStore.getAll('event_attendees'),
    ]);

    // Build set of event_ids whose activity_date falls within the 60-day window
    const recentEventIds = new Set();
    for (const a of allActivities) {
        if (a.activity_type === 'EVENT' && a.event_id && (a.activity_date || '') >= cutoffStr) {
            recentEventIds.add(String(a.event_id));
        }
    }

    // Collect active agent IDs
    const activeSet = new Set();
    // (1) Led any activity in the past 60 days
    for (const a of allActivities) {
        if (!a.lead_agent_id || (a.activity_date || '') < cutoffStr) continue;
        activeSet.add(String(a.lead_agent_id));
    }
    // (2) Attended any recent event as an agent attendee
    for (const ea of allAttendees) {
        if (ea.attendee_type !== 'agent' || !ea.entity_id) continue;
        if (!recentEventIds.has(String(ea.event_id))) continue;
        activeSet.add(String(ea.entity_id));
    }

    let count = 0;
    for (const u of users) {
        if (!isAgent(u)) continue;
        if (_visibleUserIds !== 'all' && !_visibleUserIds.map(String).includes(String(u.id))) continue;
        if (activeSet.has(String(u.id))) count++;
    }
    return count;
};

const getNewCustomers = async (from, to) => {
    const [customers, purchases] = await Promise.all([
        AppDataStore.getAll('customers'),
        AppDataStore.getAll('purchases')
    ]);
    let count = 0;
    for (const c of customers) {
        if (c.customer_since < from || c.customer_since > to) continue;
        if (_visibleUserIds !== 'all' && !_visibleUserIds.map(String).includes(String(c.responsible_agent_id))) continue;
        const hasPurchaseInRange = purchases.some(p => p.customer_id == c.id && (p.date || p.purchase_date) >= from && (p.date || p.purchase_date) <= to);
        if (!hasPurchaseInRange) continue;
        count++;
    }
    return count;
};

